+    @Test //JDK-8384229
+    public void testStaticFieldTypeLookup() throws Exception {
+        Path out = base.resolve("out");
+
+        Files.createDirectories(out);
+
+        new JavacTask(tb)
+                .options("-XDrawDiagnostics",
+                         "-XDdev")
+                .sources("""
+                         package test;
+                         import static test.A.Object;
+                         enum A {
+                             Object;
+                         }
+                         class Test {
+                             void foo() {
+                                 Object f = "";
+                             }
+                         }
+                         """)
+                .outdir(out)
+                .run()
+                .writeAll();
+
+        new JavacTask(tb)
+                .options("-XDrawDiagnostics",
+                         "-XDdev")
+                .sources("""
+                         package test;
+                         import static test.A.Object;
+                         enum A {
+                             Object;
+                         }
+                         class Test {
+                             private static final Object f = "";
+                         }
+                         """)
+                .outdir(out)
+                .run()
+                .writeAll();
+
+        new JavacTask(tb)
+                .options("-XDrawDiagnostics",
+                         "-XDdev")
+                .sources("""
+                         package test;
+                         import static test.A.Object;
+                         class A {
+                             public static java.lang.Object Object() { return null; }
+                         }
+                         class Test {
+                             private static final Object f = Object();
+                         }
+                         """)
+                .outdir(out)
+                .run()
+                .writeAll();
+    }
